mapper.select:
SELECT COUNT(*)
  FROM user_reward_history
 WHERE user_id = #{userId}
   AND event_code = #{eventCode}
   AND created_at >= CURDATE()
   AND created_at < CURDATE() + INTERVAL 1 DAY

SELECT id AS user_id, activity_point, user_level, credit
  FROM users
 WHERE id = #{userId}

mapper.update:
UPDATE users
   SET activity_point = activity_point + #{delta}
 WHERE id = #{userId}

UPDATE users
   SET user_level = #{level}
 WHERE id = #{userId}

mapper.select:
SELECT id, user_id, event_code, idempotency_key, point_delta, credit_delta, level_before, level_after,
       ref_type, ref_id, reason, created_at
  FROM user_reward_history
 WHERE user_id = #{userId}
 ORDER BY created_at DESC, id DESC
 LIMIT #{limit}
